import React, { useMemo, useState, useContext } from "react";
import {
  View,
  Text,
  Pressable,
  StyleSheet,
  Modal,
  ScrollView,
  Platform,
  useWindowDimensions,
} from "react-native";
import { Image } from "react-native";
import { AppContext } from "../../App";
import { useTranslation } from "../i18n";

import AgreementRenderer from "../legal/AgreementRenderer";

// ✅ IMPORTANT: match your real export names
import { consentAgreementBlocksEN } from "../legal/consentAgreementBlocks.en";
import { consentAgreementBlocksFR } from "../legal/consentAgreementBlocks.fr";

const COLORS = {
  primary: "#1CA7AE",
  background: "rgba(0,0,0,0.45)",
  card: "#FFFFFF",
  textDark: "#1C1C1E",
  textMuted: "#6B7280",
  border: "#E5E7EB",
  shadow: "#000",
};

// ✅ This is the key: keep header clickable by NOT covering it with the backdrop.
// Tune these if your header is taller/shorter.
const HEADER_CLEARANCE =
  Platform.OS === "web" ? 145 : Platform.OS === "ios" ? 110 : 100;

export default function ConsentModal({ onDismiss, navigation }) {
  const { setFormProgress } = useContext(AppContext);
  const { t, currentLang } = useTranslation();
  const { height } = useWindowDimensions();

  const [isChecked, setIsChecked] = useState(false);
  const [fullOpen, setFullOpen] = useState(false);

  const isFormValid = isChecked;

  // ✅ Pick EN/FR blocks based on language
  const blocks = useMemo(() => {
    return (currentLang || "en").startsWith("fr")
      ? consentAgreementBlocksFR
      : consentAgreementBlocksEN;
  }, [currentLang]);

  // ✅ Compact layout on small heights (prevents ANY scroll)
  const isCompact = height < 760;
  const previewItems = isCompact ? 10 : 14;
  const previewMinHeight = isCompact ? 120 : 160;

  const handleAccept = () => {
    if (!isFormValid) return;

    setFormProgress((prev) => ({
      ...prev,
      completedSteps: [...prev.completedSteps, "consent_modal"],
      currentStep: "find_immatriculation_or_chasis_number_screen",
    }));

    navigation.navigate("find_immatriculation_or_chasis_number_screen");
    onDismiss?.();
  };

  return (
    <View style={styles.overlay} pointerEvents="box-none">
      {/* ✅ Backdrop starts BELOW the header so header remains clickable */}
      <View style={styles.backdrop} pointerEvents="auto" />

      {/* ✅ Modal area (also starts lower so it doesn't touch the header) */}
      <View
        style={[
          styles.modalWrapper,
          isCompact && styles.modalWrapperCompact,
          { paddingTop: HEADER_CLEARANCE + (isCompact ? 16 : 24) },
        ]}
        pointerEvents="box-none"
      >
        <View
          style={[styles.modalCard, isCompact && styles.modalCardCompact]}
          pointerEvents="auto"
        >
          <Text style={[styles.title, isCompact && styles.titleCompact]}>
            {t("consent.title")}
          </Text>
          <Text style={[styles.subtitle, isCompact && styles.subtitleCompact]}>
            {t("consent.subtitle")}
          </Text>

          {/* Agreement Preview */}
          <View
            style={[styles.agreementCard, isCompact && styles.agreementCardCompact]}
          >
            <View
              style={[
                styles.agreementHeader,
                isCompact && styles.agreementHeaderCompact,
              ]}
            >
              <View style={styles.agreementHeaderLeft}>
                <View
                  style={[
                    styles.docIconWrap,
                    isCompact && styles.docIconWrapCompact,
                  ]}
                >
                  <Image
                    source={require("../../assets/handshake.png")}
                    style={[styles.docIcon, { tintColor: "#FFF" }]}
                  />
                </View>
                <Text
                  style={[
                    styles.agreementTitle,
                    isCompact && styles.agreementTitleCompact,
                  ]}
                >
                  {t("consent.fullAgreementTitle")}
                </Text>
              </View>

              <Pressable
                onPress={() => setFullOpen(true)}
                style={({ pressed }) => [
                  styles.chevBtn,
                  isCompact && styles.chevBtnCompact,
                  pressed && { opacity: 0.7 },
                ]}
                hitSlop={12}
              >
                <Text style={[styles.chev, isCompact && styles.chevCompact]}>
                  ⌃
                </Text>
              </Pressable>
            </View>

            <View style={[styles.previewWrap, { minHeight: previewMinHeight }]}>
              <AgreementRenderer blocks={blocks} maxItems={previewItems} />
              <View style={styles.previewFade} pointerEvents="none" />
            </View>

            <Pressable
              onPress={() => setFullOpen(true)}
              style={({ pressed }) => [
                styles.readFullBtn,
                isCompact && styles.readFullBtnCompact,
                pressed && { opacity: 0.9 },
              ]}
            >
              <Text
                style={[
                  styles.readFullText,
                  isCompact && styles.readFullTextCompact,
                ]}
              >
                {t("consent.readFullAgreement")}
              </Text>
              <Text
                style={[
                  styles.readFullArrow,
                  isCompact && styles.readFullArrowCompact,
                ]}
              >
                ›
              </Text>
            </Pressable>
          </View>

          {/* Checkbox */}
          <Pressable
            style={[styles.checkboxRow, isCompact && styles.checkboxRowCompact]}
            onPress={() => setIsChecked((p) => !p)}
          >
            <View style={[styles.checkbox, isChecked && styles.checkboxChecked]}>
              {isChecked && <Text style={styles.tick}>✓</Text>}
            </View>
            <Text style={[styles.checkboxText, isCompact && styles.checkboxTextCompact]}>
              {t("consent.acceptConditions")}
            </Text>
          </Pressable>

          {/* CTA */}
          <Pressable
            disabled={!isFormValid}
            onPress={handleAccept}
            style={[
              styles.acceptButton,
              isCompact && styles.acceptButtonCompact,
              !isFormValid && styles.acceptButtonDisabled,
            ]}
          >
            <Text style={[styles.acceptText, isCompact && styles.acceptTextCompact]}>
              {t("consent.accept")}
            </Text>
          </Pressable>
        </View>
      </View>

      {/* Full Agreement Modal (scroll stays here) */}
      <Modal
        transparent
        visible={fullOpen}
        animationType="fade"
        onRequestClose={() => setFullOpen(false)}
      >
        <View style={styles.fullOverlay}>
          <Pressable
            style={StyleSheet.absoluteFillObject}
            onPress={() => setFullOpen(false)}
          />
          <View style={styles.fullCard}>
            <View style={styles.fullHeader}>
              <Text style={styles.fullTitle}>{t("consent.fullAgreementTitle")}</Text>
              <Pressable
                onPress={() => setFullOpen(false)}
                hitSlop={12}
                style={({ pressed }) => pressed && { opacity: 0.7 }}
              >
                <Text style={styles.closeX}>✕</Text>
              </Pressable>
            </View>

            <ScrollView
              style={styles.fullBody}
              contentContainerStyle={styles.fullBodyContent}
              showsVerticalScrollIndicator
            >
              <AgreementRenderer blocks={blocks} />
            </ScrollView>

            <Pressable
              onPress={() => setFullOpen(false)}
              style={({ pressed }) => [
                styles.fullCloseBtn,
                pressed && { opacity: 0.9 },
              ]}
            >
              <Text style={styles.fullCloseText}>{t("common.continue")}</Text>
            </Pressable>
          </View>
        </View>
      </Modal>
    </View>
  );
}

